<script setup lang="ts">import{ref}from'vue';import{useRouter}from'vue-router';import Button from'primevue/button';import InputText from'primevue/inputtext';import Password from'primevue/password';import Message from'primevue/message';import{useAuthStore}from'../stores/auth';import{useI18n}from'../services/i18n';const username=ref('admin'),password=ref(''),loading=ref(false),error=ref(''),router=useRouter(),auth=useAuthStore(),{t}=useI18n();async function submit(){loading.value=true;error.value='';try{await auth.login(username.value,password.value);router.push('/')}catch{error.value='Неверное имя пользователя или пароль'}finally{loading.value=false}}</script>
<template><div class="h-full grid place-items-center"><form class="panel-card w-[400px] p-7 space-y-5" @submit.prevent="submit"><div class="text-center"><i class="pi pi-server text-primary text-4xl"/><h1 class="text-xl font-semibold mt-3">Mini Ubuntu Server Panel</h1></div><Message v-if="error" severity="error">{{error}}</Message><label class="block"><span class="text-sm muted">{{t.username}}</span><InputText v-model="username" class="w-full mt-1" autocomplete="username"/></label><label class="block"><span class="text-sm muted">{{t.password}}</span><Password v-model="password" class="w-full mt-1" input-class="w-full" :feedback="false" toggle-mask autocomplete="current-password"/></label><Button type="submit" :label="t.login" icon="pi pi-sign-in" class="w-full" :loading="loading"/></form></div></template>
